225→    const handleImageChange = (e) =>{
226→        const file = e.target.files[0];
227→        if(file){
228→            setImageFile(file)
229→            const reader = new FileReader();
230→            reader.onloadend = () =>{
231→                setProfilePreview(reader.result)
232→            }
233→            reader.readAsDataURL(file)
234→        }
235→    }
236→
237→    const slugifyForUsername = (val) =>
238→        String(val || '').toLowerCase().trim().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
239→
240→    const handleNameChangeForSetup = (e) => {
241→        const newName = e.target.value;
242→        setName(newName);
243→        // Auto-suggest username from name if user hasn't manually edited username
244→        if (!setupUsername || setupUsername === slugifyForUsername(name)) {
245→            const suggested = slugifyForUsername(newName);
246→            setSetupUsername(suggested);
247→            checkUsernameDebounced(suggested);
248→        }
249→    };
250→
251→    const handleUsernameChange = (e) => {
252→        const raw = e.target.value.toLowerCase().replace(/[^a-z0-9-]/g, '');
253→        setSetupUsername(raw);
254→        checkUsernameDebounced(raw);
255→    };
256→
257→    const checkUsernameDebounced = (uname) => {
258→        if (usernameCheckTimer.current) clearTimeout(usernameCheckTimer.current);
259→        if (!uname || uname.length < 3) {
260→            setUsernameAvailable(null);
261→            return;
262→        }
263→        setUsernameChecking(true);
264→        usernameCheckTimer.current = setTimeout(async () => {
265→            try {
266→                const result = await checkUsernameAvailability(uname);
267→                setUsernameAvailable(result.available);
268→            } catch {
269→                setUsernameAvailable(null);
270→            } finally {
271→                setUsernameChecking(false);
272→            }
273→        }, 400);
274→    };
275→
276→    const handleOpenTextEditor = useCallback((config = {}) => {
277→        editor.setEditable(true)
278→        setEditorLaunchConfig({
279→            ...DEFAULT_EDITOR_LAUNCH_CONFIG,
280→            ...config
281→        });
282→        setShowEditor(true)
283→    }, [editor])
