289→    const handleSubmit = async(e) =>{
290→        e.stopPropagation();
291→        e.preventDefault();
292→        try {
293→            setUploadingUserData(true)
294→            const formdata = new FormData();
295→            if(imageFile){
296→                formdata.append('image', imageFile);
297→            }
298→            if(bio && name){
299→                formdata.append('name', name)
300→                formdata.append('bio', bio)
301→                if(setupUsername && setupUsername.length >= 3){
302→                    formdata.append('username', setupUsername)
303→                }
304→            }
305→            const {data} = await submitProfileData(formdata, session?.access_token);
306→            // if(data){
307→            //     console.log(data)
308→            // }
309→            setShowWelcomeMessage(true)
310→        } catch (error) {
311→            throw new Error('error uploading data')
312→        } finally {
313→            setBio('')
314→            setName('')
